async def process(self, data: str | dict[str, Any] | None, *, run_context: RunContext[AgentDepsT], allow_partial: bool = False, wrap_validation_errors: bool = True) -> OutputDataT:
    if isinstance(data, str):
        data = _utils.strip_markdown_fences(data)

    try:
        output = self.validate(data, allow_partial=allow_partial, 
                             validation_context=run_context.validation_context)
    except ValidationError as e:
        if wrap_validation_errors:
            m = _messages.RetryPromptPart(content=e.errors(include_url=False))
            raise ToolRetryError(m) from e
        else:
            raise

    output = await self.call(output, run_context, wrap_validation_errors)
    return output
